"""Emission compliance tests for learner (auto-generated by pact)."""

from learner.learner import Learner


class TestEmissionCompliance:
    """Verify learner emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_record_decision_emits_events(self):
        """Method record_decision emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Learner(event_handler=handler)
        try:
            obj.record_decision()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for record_decision'
        assert len(completed) >= 1, 'No completed/error event for record_decision'
        assert invoked[0].get("pact_key") == "PACT:learner:record_decision"
        assert isinstance(invoked[0].get("input_classification"), list)

