    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Learner(event_handler=handler)
        try:
            obj.record_decision()
        except (TypeError, Exception):
            pass
        try:
            obj.record_human_decisions()
        except (TypeError, Exception):
            pass
        try:
            obj.get_trust_adjustments()
        except (TypeError, Exception):
            pass
        try:
            obj.check_phase_progression()
        except (TypeError, Exception):
            pass
        try:
            obj.detect_patterns()
        except (TypeError, Exception):
            pass
        try:
            obj.get_current_phase()
        except (TypeError, Exception):
            pass
        try:
            obj.should_apply_adjustments()
        except (TypeError, Exception):
            pass
        try:
            obj.get_stats()
        except (TypeError, Exception):
            pass
        try:
            obj.initialize_state()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:learner:"), f"Bad pact_key: {key}"

